from dataclasses import dataclass, field
from enum import Enum
from typing import Dict, List, Optional
import datetime


class CallerMigrationStatus(Enum):
    NOT_STARTED  = "not_started"
    IN_PROGRESS  = "in_progress"
    TESTING      = "testing"       # Migrated but running eval / canary
    COMPLETED    = "completed"
    EXCEPTION    = "exception"     # Approved extension beyond sunset date


@dataclass
class CallerMigrationRecord:
    caller_id: str            # Service or team identifier
    team_name: str
    contact_email: str
    estimated_traffic_pct: float   # Share of calls to the deprecated version
    status: CallerMigrationStatus = CallerMigrationStatus.NOT_STARTED
    migration_started_date: Optional[str] = None
    migration_completed_date: Optional[str] = None
    exception_approved_until: Optional[str] = None
    notes: str = ""

    def is_blocking_sunset(self) -> bool:
        """True if this caller would be broken by the sunset as of today."""
        if self.status == CallerMigrationStatus.COMPLETED:
            return False
        if self.status == CallerMigrationStatus.EXCEPTION:
            if self.exception_approved_until:
                return (
                    datetime.date.today()
                    > datetime.date.fromisoformat(self.exception_approved_until)
                )
        return True


@dataclass
class SunsetMigrationTracker:
    notice_id: str
    callers: List[CallerMigrationRecord] = field(default_factory=list)

    def migration_completion_rate(self) -> float:
        if not self.callers:
            return 0.0
        done = sum(
            1 for c in self.callers
            if c.status == CallerMigrationStatus.COMPLETED
        )
        return done / len(self.callers)

    def weighted_completion_rate(self) -> float:
        """Traffic-weighted completion: 100% only when high-traffic callers are done."""
        total_traffic = sum(c.estimated_traffic_pct for c in self.callers)
        if total_traffic == 0:
            return 0.0
        done_traffic = sum(
            c.estimated_traffic_pct for c in self.callers
            if c.status == CallerMigrationStatus.COMPLETED
        )
        return done_traffic / total_traffic

    def blocking_callers(self) -> List[CallerMigrationRecord]:
        return [c for c in self.callers if c.is_blocking_sunset()]

    def progress_report(self) -> str:
        blocking = self.blocking_callers()
        return (
            f"Notice {self.notice_id} migration progress:\n"
            f"  Callers: {len(self.callers)}\n"
            f"  Completion rate: {self.migration_completion_rate():.0%} by count, "
            f"{self.weighted_completion_rate():.0%} by traffic\n"
            f"  Blocking retirement: {len(blocking)} caller(s):\n"
            + "\n".join(f"    - {c.caller_id} ({c.team_name}): {c.status.value}" for c in blocking)
        )

    def safe_to_retire(self) -> bool:
        return len(self.blocking_callers()) == 0

from dataclasses import dataclass
from typing import Callable, Dict, List, Optional
import datetime


@dataclass
class SunsetEnforcementConfig:
    notice_id: str
    deprecated_version_id: str
    sunset_date: str             # ISO-8601

    # Response modifiers at each milestone
    add_warning_header_after_days_remaining: int = 60    # Add Deprecation header
    block_new_callers_after_days_remaining: int  = 30    # 409 for first-time callers
    return_gone_after_days_remaining: int        = 0     # 410 Gone after sunset

    def days_remaining(self) -> int:
        sunset = datetime.date.fromisoformat(self.sunset_date)
        return (sunset - datetime.date.today()).days

    def should_add_warning_header(self) -> bool:
        return self.days_remaining() <= self.add_warning_header_after_days_remaining

    def should_block_new_callers(self) -> bool:
        return self.days_remaining() <= self.block_new_callers_after_days_remaining

    def is_past_sunset(self) -> bool:
        return self.days_remaining() <= self.return_gone_after_days_remaining

    def enforcement_headers(self, caller_id: str, is_known_caller: bool) -> Dict[str, str]:
        """Returns HTTP headers the API gateway should add to responses for this version."""
        headers: Dict[str, str] = {}

        if self.is_past_sunset():
            # Callers receiving 410 should be redirected at the gateway layer,
            # but the header explains why.
            headers["X-Prompt-Version-Status"] = "retired"
            headers["X-Migration-Guide"] = f"https://docs.internal/sunset/{self.notice_id}"
            return headers

        if self.should_add_warning_header():
            headers["Deprecation"] = f"date=\"{self.sunset_date}\""
            headers["Sunset"] = self.sunset_date
            headers["Link"] = (
                f'<https://docs.internal/sunset/{self.notice_id}>; rel="deprecation"'
            )

        if self.should_block_new_callers() and not is_known_caller:
            headers["X-Prompt-Version-Status"] = "blocked-new-caller"

        return headers


@dataclass
class SunsetGatewayMiddleware:
    """Wraps the prompt service and enforces sunset policy at the call boundary."""
    configs: List[SunsetEnforcementConfig]
    known_callers: Dict[str, set]   # version_id -> set of caller_ids that pre-date sunset

    def resolve_enforcement(self, version_id: str, caller_id: str) -> Optional[SunsetEnforcementConfig]:
        return next((c for c in self.configs if c.deprecated_version_id == version_id), None)

    def check_and_annotate(self, version_id: str, caller_id: str) -> Dict[str, str]:
        config = self.resolve_enforcement(version_id, caller_id)
        if not config:
            return {}   # Version is not under a sunset notice
        is_known = caller_id in self.known_callers.get(version_id, set())
        return config.enforcement_headers(caller_id, is_known)
